import React, { useRef } from 'react';
import { isStandalone } from '../../dev/isStandalone';
import df from '../../styles/documentForm.module.css';
import { useTopbarAutoHideOnScroll } from './useTopbarAutoHideOnScroll';
import { useVoucherFormShellHeight } from './useVoucherFormShellHeight';

export type VoucherDocumentFormShellProps = {
  testId?: string;
  header: React.ReactNode;
  footer?: React.ReactNode;
  children: React.ReactNode;
};

export const VoucherDocumentFormShell: React.FC<VoucherDocumentFormShellProps> = ({
  testId,
  header,
  footer,
  children,
}) => {
  const shellRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  useVoucherFormShellHeight(shellRef);
  useTopbarAutoHideOnScroll(scrollRef, !isStandalone);

  return (
    <div
      ref={shellRef}
      className={df.pageVoucher}
      data-voucher-form-shell
      data-testid={testId}
    >
      <div className={df.pageFormHeader}>{header}</div>
      <div ref={scrollRef} className={df.pageFormScroll} data-testid={testId ? `${testId}-scroll` : undefined}>
        {children}
      </div>
      {footer ? <div className={df.pageFormFooter}>{footer}</div> : null}
    </div>
  );
};
